SELECT TOP 1 MIN(P.[FINAL_PRICE]) AS MIN_PRICE,
	MAX(P.[FINAL_PRICE]) AS MAX_PRICE,
	AVG(P.[FINAL_PRICE]) AS AVG_PRICE 
FROM [PRICINGS] P 
WHERE P.[IsDeleted] = 0 
	AND P.[SCHEDULE_ID] = @PRM_PRICING_SCHEDULE_ID 